    19→@freezed
    20→abstract class Session with _$Session {
    21→  const Session._();
    22→
    23→  @JsonSerializable(
    24→      explicitToJson: true, fieldRename: Constants.modelFieldRename)
    25→  const factory Session({
    26→    @Default(null) String? id,
    27→    @Default(null) String? userId,
    28→    @Default(null) String? playerId,
    29→    @Default(null) String? location,
