    46→  }) = _Session;
    47→
    48→  factory Session.fromJson(Map<String, dynamic> json) =>
    49→      _$SessionFromJson(json);
    50→
    51→  bool isEditableByUser(
    52→    String? currentUserId,
    53→    UserAccessibleContents? accessibleContents,
    54→  ) {
    55→    // same condition as isVideoUploadableByUser
    56→    return isVideoUploadableByUser(currentUserId, accessibleContents);
    57→  }
    58→
    59→  bool isVideoUploadableByUser(
    60→    String? currentUserId,
    61→    UserAccessibleContents? accessibleContents,
    62→  ) {
    63→    if (currentUserId == null || accessibleContents == null) return false;
    64→
    65→    if (teamId == null) {
    66→      return false;
    67→    }
    68→    if (accessibleContents.hasPrivilegesFor(
    69→        teamId!, RoleDomain.basic, RoleLevel.write, true)) {
    70→      return true;
    71→    }
    72→    if (userId == currentUserId &&
