AsyncCallback useSessionRefresh({
  required ValueNotifier<Session> currentSession,
}) {
  final ref = useWidgetRef();
  return useCallback(() async {
    final sessionId = currentSession.value.id;
    final teamId = currentSession.value.teamId;

    if (sessionId == null || teamId == null) return;

    final res = await ref
        .read(sessionListControllerProvider.notifier)
        .refreshSpecificSesison(teamId: teamId, sessionId: sessionId);

    if (res.hasRight) {
      currentSession.value = res.right;

      // TODO: サーバー側の対応完了後に aiCoachReportId だけにする
      final reportId = res.right.aiCoachReportId ?? res.right.aiCoachReport?.id;
      if (reportId != null) {
        ref.invalidate(
          aICoachReportControllerProvider(
            teamId: teamId,
            reportId: reportId,
          ),
        );
      }
    }

    ref
        .read(resourceDataListControllerProvider(
          teamId: teamId,
          sessionId: currentSession.value.id!,
        ).notifier)
        .forceRefresh();

    ref.invalidate(teamListControllerProvider);

    await ref.read(resourceDataListControllerProvider(
      teamId: teamId,
      sessionId: currentSession.value.id!,
    ).future);
  }, [currentSession.value.id]);
}

